1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUE: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_PREMIUM = 60;
52	const DEDUCTIBLE = 100;
53	const CAP_MULTIPLIER = 2;
54	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
55	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
56	const FULL_REIMBURSEMENT_RATE = 1;
57	
58	const FIRST_INSURANCE_SURCHARGE = 0.1;
59	const CURSE_SURCHARGE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	const LOYALTY_DISCOUNT = 0.2;
63	const LOYALTY_THRESHOLD_YEARS = 2;
64	const FOLLOWUP_DISCOUNT = 0.15;
65	const PROCESSING_FEE = 5;
66	
67	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
68	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
69	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
70	
71	// A block applies only to a group of exactly BLOCK_SIZE alike components,
72	// priced at BLOCK_PREMIUM; any other count is priced individually.
73	const componentBasePremium = (count: number, perComponent: number): number => {
74	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
75	  return count * perComponent;
76	};
77	
78	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
79	
80	const isKnownItemType = (type: string): boolean => BASE_PREMIUM[type] !== undefined;
81	
82	// A quote may only insure item types the office prices. An unknown type has no
83	// premium or insurance value, so we reject the whole quote rather than guess.
84	const assertKnownItemTypes = (items: Item[]): void => {
85	  const unknown = items.find((item) => !isKnownItemType(item.type));
86	  if (unknown !== undefined) {
87	    throw new Error(`Unknown item type: ${unknown.type}`);
88	  }
89	};
90	
91	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
92	const isMainItem = (item: Item): boolean => !isComponent(item);
93	
94	const countByType = (items: Item[]): Record<string, number> => {
95	  const counts: Record<string, number> = {};
96	  for (const item of items) {
97	    counts[item.type] = (counts[item.type] ?? 0) + 1;
98	  }
99	  return counts;
100	};
101	
102	// A surcharge rate is an additive percentage applied on top of a base premium.
103	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
104	
105	// A conditional rate: the given percentage when its condition holds, else 0.
106	// Used for both item surcharges and policy-wide discounts.
107	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
108	
109	// Item-specific surcharges are additive percentages of the item's base premium.
110	// First insurance applies to every item; the others only when their condition holds.
111	const itemSurchargeRate = (item: Item): number =>
112	  sum([
113	    FIRST_INSURANCE_SURCHARGE,
114	    rateWhen(item.cursed === true, CURSE_SURCHARGE),
115	    rateWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
116	  ]);
117	
118	const mainItemPremium = (item: Item): number =>
119	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
120	
121	const componentGroupBases = (items: Item[]): number[] =>
122	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
123	    componentBasePremium(count, BASE_PREMIUM[type]),
124	  );
125	
126	// Sum of item base premiums with block pricing but no surcharges; the basis
127	// for policy-wide modifiers (loyalty, follow-up).
128	const policyBasePremium = (items: Item[]): number =>
129	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
130	  sum(componentGroupBases(items));
131	
132	// Sum of item premiums including item-specific surcharges (curse, high
133	// enchantment, first insurance).
134	const itemsPremium = (items: Item[]): number => {
135	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
136	  const componentsPremium = sum(
137	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
138	  );
139	  return mainItemsPremium + componentsPremium;
140	};
141	
142	// Policy-wide discounts are a rate applied to the unmodified policy base.
143	// Loyalty is one such discount; the follow-up-contract discount will be another.
144	const policyWideDiscount = (rate: number, policyBase: number): number => rate * policyBase;
145	
146	const loyaltyDiscountRate = (yearsWithMHPCO: number): number =>
147	  rateWhen(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT);
148	
149	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowup: boolean): number => {
150	  const surcharged = itemsPremium(items);
151	  const policyBase = policyBasePremium(items);
152	  const discountRate = loyaltyDiscountRate(yearsWithMHPCO) + rateWhen(isFollowup, FOLLOWUP_DISCOUNT);
153	  const discount = policyWideDiscount(discountRate, policyBase);
154	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
155	};
156	
157	const insuranceSum = (items: Item[]): number =>
158	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
159	
160	const findInsuredItem = (policyItems: Item[], itemType: string): Item | undefined =>
161	  policyItems.find((item) => item.type === itemType);
162	
163	const isHighlyEnchanted = (item: Item | undefined): boolean =>
164	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
165	
166	// The damaged item's traits decide what fraction of the damage is reimbursed
167	// before the deductible. Clauses are checked in priority order, so the first
168	// matching one wins; a full reimbursement applies when none does.
169	const reimbursementRate = (item: Item | undefined): number => {
170	  if (isHighlyEnchanted(item)) return HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
171	  return FULL_REIMBURSEMENT_RATE;
172	};
173	
174	const reimbursement = (item: Item | undefined, amount: number): number =>
175	  amount * reimbursementRate(item);
176	
177	const damagePayout = (damage: Damage, item: Item | undefined): number =>
178	  Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
179	
180	const countByItemType = (damages: Damage[]): Record<string, number> => {
181	  const counts: Record<string, number> = {};
182	  for (const damage of damages) {
183	    counts[damage.itemType] = (counts[damage.itemType] ?? 0) + 1;
184	  }
185	  return counts;
186	};
187	
188	// A claim may only report as many damages of a type as the policy insures of
189	// that type; an uninsured type insures zero, so it is rejected too.
190	const assertDamagesWithinInsuredCounts = (policyItems: Item[], damages: Damage[]): void => {
191	  const insured = countByType(policyItems);
192	  const damaged = countByItemType(damages);
193	  const excessType = Object.keys(damaged).find((type) => damaged[type] > (insured[type] ?? 0));
194	  if (excessType !== undefined) {
195	    throw new Error(`Too many damages for item type: ${excessType}`);
196	  }
197	};
198	
199	// The uncapped payout an incident would pay before the policy's remaining cap
200	// is applied: each damage reimbursed per its item's clause, less the deductible.
201	const incidentPayout = (policyItems: Item[], incident: ClaimStep["incident"]): number =>
202	  sum(
203	    incident.damages.map((damage) =>
204	      damagePayout(damage, findInsuredItem(policyItems, damage.itemType)),
205	    ),
206	  );
207	
208	interface Policy {
209	  items: Item[];
210	  remainingCap: number;
211	}
212	
213	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
214	  const { yearsWithMHPCO } = scenario.customer;
215	  const policies: Record<number, Policy> = {};
216	  let quoteCount = 0;
217	
218	  const handleQuote = (step: QuoteStep, index: number): { premium: number } => {
219	    assertKnownItemTypes(step.items);
220	    policies[index] = {
221	      items: step.items,
222	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
223	    };
224	    const isFollowup = quoteCount > 0;
225	    quoteCount += 1;
226	    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
227	  };
228	
229	  const handleClaim = (step: ClaimStep): { payout: number; remainingCap: number } => {
230	    const policy = policies[step.policy];
231	    assertDamagesWithinInsuredCounts(policy.items, step.incident.damages);
232	    const desiredPayout = incidentPayout(policy.items, step.incident);
233	    const payout = Math.min(desiredPayout, policy.remainingCap);
234	    policy.remainingCap -= payout;
235	    return { payout, remainingCap: policy.remainingCap };
236	  };
237	
238	  const results = scenario.steps.map((step, index) =>
239	    step.op === "claim" ? handleClaim(step) : handleQuote(step, index),
240	  );
241	
242	  return { results };
243	};
